{"cells":[{"cell_type":"code","source":["# Mount Google Drive to access analysis files.\n","\n","from google.colab import drive\n","drive.mount('/content/drive')\n","\n","dir_path = '/content/drive/MyDrive/Personal/Sues/'"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"qT8R9DKfEyy0","executionInfo":{"status":"ok","timestamp":1761628824287,"user_tz":-660,"elapsed":22624,"user":{"displayName":"Tomer","userId":"10873557234236150514"}},"outputId":"01e0beab-6c1a-43c1-aa76-151fa0626e7b"},"execution_count":1,"outputs":[{"output_type":"stream","name":"stdout","text":["Mounted at /content/drive\n"]}]},{"cell_type":"code","source":["# Load required libraries.\n","\n","import requests\n","import pandas as pd\n","import re\n","from bs4 import BeautifulSoup\n","from tqdm import tqdm\n","import time\n","import json\n","import os\n","import sys"],"metadata":{"id":"UqnlAcadE7ci","executionInfo":{"status":"ok","timestamp":1761628886615,"user_tz":-660,"elapsed":741,"user":{"displayName":"Tomer","userId":"10873557234236150514"}}},"execution_count":2,"outputs":[]},{"cell_type":"code","source":["# --- 1. CONFIGURATION ---\n","\n","# Define input and output files\n","# This script assumes 'unit_list.csv' and 'search_terms.json' are in the same directory.\n","SEARCH_TERMS_FILE = dir_path + 'search_terms.json'\n","INPUT_FILE = dir_path + 'unit_list.csv'\n","STRICT_OUTPUT_FILE = dir_path + 'term_analysis_strict.csv'\n","SENSITIVE_OUTPUT_FILE = dir_path + 'term_analysis_sensitive.csv'\n","\n","# --- 2. CORE FUNCTIONS ---\n","\n","def scrape_unit_page(unit_url):\n","    \"\"\"\n","    Scrapes the content of a single unit page using the \"remove the noise\" strategy\n","    to make it generalizable to other university handbooks.\n","\n","    Args:\n","        unit_url (str): The URL of the unit handbook page.\n","\n","    Returns:\n","        str: Cleaned text content of the page, or None if scraping fails.\n","    \"\"\"\n","    try:\n","        response = requests.get(unit_url, timeout=10) # Added a timeout\n","\n","        # Check for a successful request\n","        if response.status_code != 200:\n","            # Print errors to stderr\n","            print(f\"  [!] Failed to fetch {unit_url} (Status: {response.status_code})\", file=sys.stderr)\n","            return None\n","\n","        soup = BeautifulSoup(response.text, 'html.parser')\n","\n","        # Decompose (find and destroy) all common \"noise\" tags\n","        for tag in soup(['nav', 'header', 'footer', 'aside', 'script', 'style']):\n","            tag.decompose()\n","\n","        # Get the text from the remaining body.\n","        # Using a space separator ensures words don't get mushed together.\n","        if soup.body:\n","            return soup.body.get_text(separator=' ')\n","        else:\n","            print(f\"  [!] No <body> tag found in {unit_url}\", file=sys.stderr)\n","            return None\n","\n","    except requests.exceptions.RequestException as e:\n","        print(f\"  [!] Network error for {unit_url}: {e}\", file=sys.stderr)\n","        return None\n","\n","def analyze_content_strict(text, unit_details, search_terms_dict):\n","    \"\"\"\n","    Analyzes text using the \"Strict\" (high-precision) regex search.\n","    Finds \"man\" but not \"manual\".\n","\n","    Args:\n","        text (str): The text content from the unit page.\n","        unit_details (pd.Series): The row from the *unique* unit DataFrame.\n","        search_terms_dict (dict): The dictionary of terms loaded from JSON.\n","\n","    Returns:\n","        list: A list of \"hit\" dictionaries.\n","    \"\"\"\n","    hits_list = []\n","    lower_text = text.lower()\n","\n","    # Split text into sentences for context-grabbing.\n","    try:\n","        # This regex splits on periods, ?, and ! that are followed by a space\n","        sentences = re.split(r'(?<!\\w\\w.)(?<![A-Z][a-z])(?<=\\.|\\?|\\!)\\s', text)\n","    except Exception:\n","        # Fallback for very complex/weird text\n","        sentences = text.split('. ')\n","\n","    for category, terms in search_terms_dict.items():\n","        for term in terms:\n","            try:\n","                # Escape the term to handle special characters (like in \"trans*\")\n","                escaped_term = re.escape(term)\n","\n","                # Regex Explanation:\n","                # (^|\\s|-)    : Must be preceded by start of string, space, or dash\n","                # (           : Start capturing group for the term itself\n","                # {escaped_term} : The term we are looking for\n","                # )           : End capturing group\n","                # (?![a-zA-Z]) : Negative lookahead: NOT followed by a letter\n","                regex_pattern = r\"(^|\\s|-)(\" + escaped_term + r\")(?![a-zA-Z])\"\n","\n","                matches = re.findall(regex_pattern, lower_text, re.IGNORECASE)\n","                term_count = len(matches)\n","\n","                if term_count > 0:\n","                    # Term was found, now find the context\n","                    context_sentences = [\n","                        s.strip() for s in sentences\n","                        if re.search(regex_pattern, s, re.IGNORECASE)\n","                    ]\n","                    context_string = \" | \".join(context_sentences)\n","\n","                    # Create a record with unit-specific info\n","                    hits_list.append({\n","                        'Unit Code': unit_details['Unit Code'],\n","                        'Unit Title': unit_details['Unit Title'],\n","                        'Unit Link': unit_details['Unit Link'],\n","                        'Term Found': term,\n","                        'Term Category': category,\n","                        'Count': term_count,\n","                        'Context (Sentences)': context_string\n","                    })\n","            except Exception as e:\n","                print(f\"[!] Regex error for term '{term}': {e}\", file=sys.stderr)\n","\n","    return hits_list\n","\n","def analyze_content_sensitive(text, unit_details, search_terms_dict):\n","    \"\"\"\n","    Analyzes text using the \"Sensitive\" (high-recall) simple string .count() search.\n","    Finds \"man\" AND \"manual\".\n","\n","    Args:\n","        text (str): The text content from the unit page.\n","        unit_details (pd.Series): The row from the *unique* unit DataFrame.\n","        search_terms_dict (dict): The dictionary of terms loaded from JSON.\n","\n","    Returns:\n","        list: A list of \"hit\" dictionaries.\n","    \"\"\"\n","    hits_list = []\n","    lower_text = text.lower()\n","\n","    try:\n","        sentences = re.split(r'(?<!\\w\\w.)(?<![A-Z][a-z])(?<=\\.|\\?|\\!)\\s', text)\n","    except Exception:\n","        sentences = text.split('. ')\n","\n","    for category, terms in search_terms_dict.items():\n","        for term in terms:\n","            lower_term = term.lower()\n","            term_count = lower_text.count(lower_term)\n","\n","            if term_count > 0:\n","                # Term was found, now find the context\n","                context_sentences = [\n","                    s.strip() for s in sentences\n","                    if lower_term in s.lower()\n","                ]\n","                context_string = \" | \".join(context_sentences)\n","\n","                # Create a record with unit-specific info\n","                hits_list.append({\n","                    'Unit Code': unit_details['Unit Code'],\n","                    'Unit Title': unit_details['Unit Title'],\n","                    'Unit Link': unit_details['Unit Link'],\n","                    'Term Found': term,\n","                    'Term Category': category,\n","                    'Count': term_count,\n","                    'Context (Sentences)': context_string\n","                })\n","\n","    return hits_list\n","\n","def map_and_save_results(full_df, hits_df, output_filename, analysis_type):\n","    \"\"\"\n","    Maps analysis results to the full course list using a DataFrame merge.\n","\n","    Args:\n","        full_df (pd.DataFrame): The original, complete DataFrame from 'unit_list.csv'.\n","        hits_df (pd.DataFrame): The DataFrame of hits from the analysis (unit-info only).\n","        output_filename (str): The name of the file to save.\n","        analysis_type (str): A string name for logging (e.g., \"Strict\").\n","    \"\"\"\n","    print(f\"\\nMerging {analysis_type} results with full course list...\")\n","\n","    if hits_df.empty:\n","        print(f\"\\n{analysis_type} analysis complete. No occurrences of any search terms were found.\")\n","        return\n","\n","    # Use an inner merge.\n","    # It joins the full list (with courses) to the hits list (with terms)\n","    # only on rows where a hit was found, automatically mapping\n","    # all course data to the corresponding hits.\n","    df_analysis = pd.merge(\n","        left=full_df,\n","        right=hits_df,\n","        on=['Unit Link', 'Unit Code', 'Unit Title'], # Use all common keys for a robust join\n","        how='inner' # 'inner' join keeps only units that are in both DataFrames (i.e., had hits)\n","    )\n","\n","    print(f\"\\nMerge complete. Generated {len(df_analysis)} total {analysis_type} term occurrences.\")\n","\n","    # Save to DataFrame\n","    try:\n","        # Define and set column order\n","        columns_order = [\n","            'Course Code', 'Course Title', 'Unit Code', 'Unit Title', 'Term Category',\n","            'Term Found', 'Count', 'Context (Sentences)', 'Unit Link'\n","        ]\n","        # Use reindex to ensure column order is correct\n","        df_analysis = df_analysis.reindex(columns=columns_order)\n","\n","        df_analysis.to_csv(output_filename, index=False, encoding='utf-8')\n","\n","        print(f\"Successfully saved {analysis_type} analysis to '{output_filename}'\")\n","\n","        # Print a summary of findings\n","        print(f\"\\n--- Top 10 {analysis_type} Terms Found ---\")\n","        print(df_analysis['Term Found'].value_counts().head(10).to_string())\n","\n","    except Exception as e:\n","        print(f\"\\n[ERROR] Failed to save {analysis_type} results to CSV: {e}\", file=sys.stderr)\n"],"outputs":[],"execution_count":7,"metadata":{"id":"VKEVQtMLA54I","executionInfo":{"status":"ok","timestamp":1761629253318,"user_tz":-660,"elapsed":37,"user":{"displayName":"Tomer","userId":"10873557234236150514"}}}},{"cell_type":"code","source":["# --- 3. MAIN EXECUTION ---\n","\n","def main():\n","    \"\"\"\n","    Main script execution.\n","    1. Loads search terms from JSON.\n","    2. Loads unit list from CSV.\n","    3. Creates a de-duplicated list of units to scrape.\n","    4. Loops through each *unique* unit, scrapes, and runs BOTH analyses.\n","    5. [CHANGED] Caches results for both analyses in simple lists.\n","    6. [CHANGED] Converts caches to DataFrames.\n","    7. [CHANGED] Maps both DataFrames to the *full* original list using pd.merge.\n","    8. Saves all \"hits\" to two separate CSVs.\n","    \"\"\"\n","    print(f\"Starting dual unit content analysis...\")\n","\n","    # 1. Load search terms from JSON\n","    try:\n","        with open(SEARCH_TERMS_FILE, 'r', encoding='utf-8') as f:\n","            search_terms = json.load(f)\n","        print(f\"Successfully loaded {sum(len(v) for v in search_terms.values())} terms from '{SEARCH_TERMS_FILE}'\")\n","    except FileNotFoundError:\n","        print(f\"[ERROR] Search terms file '{SEARCH_TERMS_FILE}' not found.\", file=sys.stderr)\n","        return\n","    except json.JSONDecodeError as e:\n","        print(f\"[ERROR] Could not parse '{SEARCH_TERMS_FILE}'. Check JSON format: {e}\", file=sys.stderr)\n","        return\n","    except Exception as e:\n","        print(f\"[ERROR] Could not read '{SEARCH_TERMS_FILE}': {e}\", file=sys.stderr)\n","        return\n","\n","    # 2. Read input CSV\n","    try:\n","        df_units = pd.read_csv(INPUT_FILE)\n","        if 'Unit Link' not in df_units.columns:\n","            print(f\"[ERROR] Input file '{INPUT_FILE}' must have a 'Unit Link' column.\", file=sys.stderr)\n","            return\n","    except FileNotFoundError:\n","        print(f\"[ERROR] Input file '{INPUT_FILE}' not found.\", file=sys.stderr)\n","        print(\"Please run the first script (deakin_unit_scraper.py) and save its output to 'unit_list.csv'.\", file=sys.stderr)\n","        return\n","    except Exception as e:\n","        print(f\"[ERROR] Could not read '{INPUT_FILE}': {e}\", file=sys.stderr)\n","        return\n","\n","    # 3. Create a de-duplicated list of units to scrape.\n","    print(f\"Loaded {len(df_units)} total course-unit entries.\")\n","    df_unique_units = df_units.drop_duplicates(subset=['Unit Link']).copy()\n","    print(f\"Found {len(df_unique_units)} unique units to scrape. Starting scrape...\")\n","\n","    # 4. Scrape unique units and cache results for BOTH analyses\n","    # [CHANGED] Use simple lists to store hits\n","    strict_hits_list = []\n","    sensitive_hits_list = []\n","\n","    # Use tqdm for a progress bar\n","    for index, row in tqdm(df_unique_units.iterrows(), total=df_unique_units.shape[0], desc=\"Analyzing Units\"):\n","\n","        content = scrape_unit_page(row['Unit Link'])\n","\n","        if content:\n","            # Run BOTH analyses on the same content\n","            strict_hits = analyze_content_strict(content, row, search_terms)\n","            sensitive_hits = analyze_content_sensitive(content, row, search_terms)\n","\n","            # [CHANGED] Extend the lists with the new hits\n","            if strict_hits:\n","                strict_hits_list.extend(strict_hits)\n","            if sensitive_hits:\n","                sensitive_hits_list.extend(sensitive_hits)\n","\n","        time.sleep(0.05) # Be polite, pause briefly between requests\n","\n","    print(\"\\nScraping complete.\")\n","\n","    # 5. Convert lists to DataFrames\n","    df_strict_hits = pd.DataFrame(strict_hits_list)\n","    df_sensitive_hits = pd.DataFrame(sensitive_hits_list)\n","\n","    # 6. Map and save results for both DataFrames\n","    map_and_save_results(df_units, df_strict_hits, STRICT_OUTPUT_FILE, \"Strict\")\n","    map_and_save_results(df_units, df_sensitive_hits, SENSITIVE_OUTPUT_FILE, \"Sensitive\")\n","\n","    print(\"\\nDual analysis is complete.\")\n","\n","if __name__ == \"__main__\":\n","    main()"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"vLH25_wQIg1e","executionInfo":{"status":"ok","timestamp":1761630415554,"user_tz":-660,"elapsed":1049372,"user":{"displayName":"Tomer","userId":"10873557234236150514"}},"outputId":"a492321d-e384-445d-b8ba-1699353159bb"},"execution_count":10,"outputs":[{"output_type":"stream","name":"stdout","text":["Starting dual unit content analysis...\n","Successfully loaded 144 terms from '/content/drive/MyDrive/Personal/Sues/search_terms.json'\n","Loaded 965 total course-unit entries.\n","Found 560 unique units to scrape. Starting scrape...\n"]},{"output_type":"stream","name":"stderr","text":["Analyzing Units:   5%|▌         | 28/560 [00:52<15:19,  1.73s/it]  [!] Network error for http://handbook.deakin.edu.au/current-students-courses/unit.php?unit=SIT190: ('Connection aborted.', RemoteDisconnected('Remote end closed connection without response'))\n","Analyzing Units: 100%|██████████| 560/560 [17:27<00:00,  1.87s/it]\n"]},{"output_type":"stream","name":"stdout","text":["\n","Scraping complete.\n","\n","Merging Strict results with full course list...\n","\n","Merge complete. Generated 252 total Strict term occurrences.\n","Successfully saved Strict analysis to '/content/drive/MyDrive/Personal/Sues/term_analysis_strict.csv'\n","\n","--- Top 10 Strict Terms Found ---\n","Term Found\n","midwifery       47\n","transition      34\n","Gender          29\n","pregnancy       15\n","Sexuality       14\n","Reproduction    13\n","Women           11\n","Sexual           9\n","Woman            8\n","Maternity        8\n","\n","Merging Sensitive results with full course list...\n","\n","Merge complete. Generated 3074 total Sensitive term occurrences.\n","Successfully saved Sensitive analysis to '/content/drive/MyDrive/Personal/Sues/term_analysis_sensitive.csv'\n","\n","--- Top 10 Sensitive Terms Found ---\n","Term Found\n","Men           846\n","Man           844\n","STI           838\n","Trans         125\n","midwifery      47\n","Wife           47\n","midwife        47\n","transition     38\n","Gender         30\n","PID            29\n","\n","Dual analysis is complete.\n"]}]},{"cell_type":"code","source":[],"metadata":{"id":"6g_tuv2KSMSp"},"execution_count":null,"outputs":[]}],"metadata":{"colab":{"provenance":[]},"kernelspec":{"display_name":"Python 3","name":"python3"}},"nbformat":4,"nbformat_minor":0}